import androidx.compose.ui.unit.sp
import androidx.compose.ui.viewinterop.AndroidView
import androidx.core.content.ContextCompat
import com.example.palmistry.ui.theme.*

@Composable
fun CameraScreen(
    selectedLanguage: String,
    onPalmMetadataReady: (String) -> Unit,
    onNavigateHome: () -> Unit
) {
    val context = LocalContext.current
    val lifecycleOwner = LocalLifecycleOwner.current

    var isFlashOn by remember { mutableStateOf(false) }
    var cameraControl: Camera? by remember { mutableStateOf(null) }
    var userQuestionText by remember { mutableStateOf("") }

    Box(modifier = Modifier.fillMaxSize()) {
        AndroidView(
            factory = { ctx ->
                PreviewView(ctx).apply {
                    layoutParams = ViewGroup.LayoutParams(
                        ViewGroup.LayoutParams.MATCH_PARENT,
                        ViewGroup.LayoutParams.MATCH_PARENT
                    )
                    scaleType = PreviewView.ScaleType.FILL_CENTER
                }
            },
            update = { previewView ->
                val cameraProviderFuture = ProcessCameraProvider.getInstance(context)
                cameraProviderFuture.addListener({
                    val cameraProvider = cameraProviderFuture.get()
                    val preview = Preview.Builder().build().also {
                        it.setSurfaceProvider(previewView.surfaceProvider)
                    }
                    val cameraSelector = CameraSelector.DEFAULT_BACK_CAMERA

                    try {
                        cameraProvider.unbindAll()
                        val cam = cameraProvider.bindToLifecycle(
                            lifecycleOwner,
                            cameraSelector,
                            preview
                        )
                        cameraControl = cam
                    } catch (e: Exception) {
                        Log.e("CameraScreen", "Use case binding failed", e)
                    }
                }, ContextCompat.getMainExecutor(context))
            },
            modifier = Modifier.fillMaxSize()
        )

        // Animated Palm Overlay Guide
        AnimatedPalmOverlay()

        // Top Action Bar: Home Button & Flashlight Toggle Button
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .statusBarsPadding()
                .padding(16.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            // 🏠 Home Button
            IconButton(
                onClick = onNavigateHome,
                modifier = Modifier
                    .size(48.dp)
                    .background(CardDark.copy(alpha = 0.85f), shape = CircleShape)
            ) {
                Text(text = "🏠", fontSize = 20.sp)
            }

            // ⚡ Flashlight Toggle Button
            IconButton(
                onClick = {
                    isFlashOn = !isFlashOn
                    cameraControl?.cameraControl?.enableTorch(isFlashOn)
                },
                modifier = Modifier
                    .size(48.dp)
                    .background(
                        if (isFlashOn) GoldAccent else CardDark.copy(alpha = 0.85f),
                        shape = CircleShape
                    )
            ) {
                Text(text = if (isFlashOn) "⚡ ON" else "💡 OFF", fontSize = 14.sp, color = if (isFlashOn) DeepPurple else SoftWhite)
            }
        }

        // Bottom Controls: Optional Question Input & Capture / Scan Button
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .align(Alignment.BottomCenter)
                .navigationBarsPadding()
                .padding(20.dp),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            // Optional Specific Question Input (e.g. Shadi kab hogi / Job kab lagegi)
            OutlinedTextField(
                value = userQuestionText,
                onValueChange = { userQuestionText = it },
                placeholder = { Text("Poshain: Shadi, Job ya Dhan kab milne ka yog hai...", color = SoftWhite.copy(alpha = 0.6f), fontSize = 13.sp) },
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(bottom = 16.dp),
                shape = RoundedCornerShape(14.dp),
                colors = OutlinedTextFieldDefaults.colors(
                    focusedContainerColor = CardDark.copy(alpha = 0.9f),
                    unfocusedContainerColor = CardDark.copy(alpha = 0.8f),
                    focusedBorderColor = GoldAccent,
                    unfocusedBorderColor = NeonViolet,
                    focusedTextColor = SoftWhite,
                    unfocusedTextColor = SoftWhite
                )
            )

            // Capture / Scan Palm Photo Button
            Button(
                onClick = {
                    val finalQuestion = if (userQuestionText.isNotBlank()) userQuestionText else "Aapka poora Hastrekha Bhavishyavani vivran vistar se dein."
                    val sampleMetadata = """{
                        "hand": "Right",
                        "language": "$selectedLanguage",
                        "userQuestion": "$finalQuestion",
                        "lifeLineScore": 0.88,
                        "heartLineScore": 0.92,
                        "headLineScore": 0.85,
                        "fateLineScore": 0.80,
                        "confidenceScore": 0.90
                    }""".trimIndent()
                    onPalmMetadataReady(sampleMetadata)
                },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(56.dp),
                shape = RoundedCornerShape(16.dp),
                colors = ButtonDefaults.buttonColors(containerColor = GoldAccent)
            ) {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Text(text = "📸", fontSize = 22.sp)
                    Spacer(modifier = Modifier.width(10.dp))
                    Text(
                        text = "CLICK PHOTO & SCAN PALM",
                        fontSize = 16.sp,
                        fontWeight = FontWeight.Bold,
                        color = DeepPurple
                    )
                }
            }
        }
    }
}

package com.example.palmistry.ui.navigation

import androidx.compose.runtime.*
import androidx.hilt.navigation.compose.hiltViewModel
import androidx.navigation.NavHostController
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.navArgument
import com.example.palmistry.ui.CameraScreen
import com.example.palmistry.ui.HomeScreen
import com.example.palmistry.ui.ReadingHistoryScreen
import com.example.palmistry.ui.ReadingResultScreen
import com.example.palmistry.ui.viewmodel.HistoryViewModel
import com.example.palmistry.ui.viewmodel.PalmistryViewModel
import java.net.URLDecoder
import java.nio.charset.StandardCharsets

object Routes {
    const val HOME    = "home"
    const val CAMERA  = "camera"
    const val RESULT  = "result/{reading}"
    const val HISTORY = "history"

    fun resultRoute(reading: String): String = "result/${java.net.URLEncoder.encode(reading, StandardCharsets.UTF_8.toString())}"
}

@Composable
fun NavGraph(
    navController: NavHostController,
    startDestination: String = Routes.HOME,
    palmViewModel: PalmistryViewModel = hiltViewModel(),
    historyViewModel: HistoryViewModel = hiltViewModel()
) {
    var selectedLanguage by remember { mutableStateOf("Bilingual") }

    NavHost(
        navController = navController,
        startDestination = startDestination
    ) {
        // Home Landing Dashboard Screen
        composable(Routes.HOME) {
            HomeScreen(
                selectedLanguage = selectedLanguage,
                onLanguageSelected = { selectedLanguage = it },
                onStartScan = { navController.navigate(Routes.CAMERA) },
                onOpenHistory = { navController.navigate(Routes.HISTORY) }
            )
        }

        // Camera Scanner Screen with Flashlight & Capture
        composable(Routes.CAMERA) {
            CameraScreen(
                selectedLanguage = selectedLanguage,
                onPalmMetadataReady = { palmJson ->
                    palmViewModel.generateReading(palmJson)
                },
                onNavigateHome = {
                    navController.navigate(Routes.HOME) {
                        popUpTo(Routes.HOME) { inclusive = true }
                    }
                }
            )
        }

        // Result screen with decoded reading text
        composable(
            route = Routes.RESULT,
            arguments = listOf(navArgument("reading") { type = NavType.StringType })
        ) { backStackEntry ->
            val encoded = backStackEntry.arguments?.getString("reading") ?: ""
            val reading = URLDecoder.decode(encoded, StandardCharsets.UTF_8.toString())
            ReadingResultScreen(
                readingResult = reading,
                onBackToHome = { navController.navigate(Routes.HOME) { popUpTo(Routes.HOME) { inclusive = true } } }
            )
        }

        // History screen
        composable(Routes.HISTORY) {
            val readings by historyViewModel.readings.collectAsState(initial = emptyList())
            ReadingHistoryScreen(
                readings = readings,
                onDelete = { id -> historyViewModel.deleteReading(id) }
            )
        }
    }
}

package com.example.palmistry.ui

import androidx.compose.animation.*
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
