package com.example.palmistry.ui.navigation

import androidx.compose.runtime.*
import androidx.hilt.navigation.compose.hiltViewModel
import androidx.navigation.NavHostController
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.navArgument
import com.example.palmistry.ui.CameraScreen
import com.example.palmistry.ui.HomeScreen
import com.example.palmistry.ui.InteractiveChatScreen
import com.example.palmistry.ui.ReadingHistoryScreen
import com.example.palmistry.ui.viewmodel.HistoryViewModel
import com.example.palmistry.ui.viewmodel.PalmistryViewModel
import java.net.URLDecoder
import java.nio.charset.StandardCharsets

object Routes {
    const val HOME    = "home"
    const val CAMERA  = "camera"
    const val RESULT  = "result/{reading}"
    const val HISTORY = "history"

    fun resultRoute(reading: String): String = "result/${java.net.URLEncoder.encode(reading, StandardCharsets.UTF_8.toString())}"
}

@Composable
fun NavGraph(
    navController: NavHostController,
    startDestination: String = Routes.HOME,
    palmViewModel: PalmistryViewModel = hiltViewModel(),
    historyViewModel: HistoryViewModel = hiltViewModel()
) {
    var selectedLanguage by remember { mutableStateOf("Bilingual") }
    var currentPalmMetadataJson by remember { mutableStateOf("") }

    NavHost(
        navController = navController,
        startDestination = startDestination
    ) {
        // Home Landing Dashboard Screen
        composable(Routes.HOME) {
            HomeScreen(
                selectedLanguage = selectedLanguage,
                onLanguageSelected = { selectedLanguage = it },
                onStartScan = { navController.navigate(Routes.CAMERA) },
                onOpenHistory = { navController.navigate(Routes.HISTORY) }
            )
        }

        // Camera Scanner Screen with Flashlight & Capture
        composable(Routes.CAMERA) {
            CameraScreen(
                selectedLanguage = selectedLanguage,
                onPalmMetadataReady = { palmJson ->
                    currentPalmMetadataJson = palmJson
                    palmViewModel.generateReading(palmJson)
                },
                onNavigateHome = {
                    navController.navigate(Routes.HOME) {
                        popUpTo(Routes.HOME) { inclusive = true }
                    }
                }
            )
        }

        // Interactive Multi-Question Chat Screen
        composable(
            route = Routes.RESULT,
            arguments = listOf(navArgument("reading") { type = NavType.StringType })
        ) { backStackEntry ->
            val encoded = backStackEntry.arguments?.getString("reading") ?: ""
            val reading = URLDecoder.decode(encoded, StandardCharsets.UTF_8.toString())
            InteractiveChatScreen(
                initialReading = reading,
                palmMetadataJson = currentPalmMetadataJson,
                selectedLanguage = selectedLanguage,
                onSendFollowUpQuestion = { question, onResponseReady ->
                    val followUpPayload = """{
                        "hand": "Right",
                        "language": "$selectedLanguage",
                        "userQuestion": "$question",
                        "lifeLineScore": 0.88,
                        "heartLineScore": 0.92,
                        "headLineScore": 0.85,
                        "fateLineScore": 0.80,
                        "confidenceScore": 0.90
                    }""".trimIndent()
                    palmViewModel.generateReadingDirect(followUpPayload, onResponseReady)
                },
                onBackToHome = {
                    navController.navigate(Routes.HOME) {
                        popUpTo(Routes.HOME) { inclusive = true }
                    }
                }
            )
        }

        // History screen
        composable(Routes.HISTORY) {
            val readings by historyViewModel.readings.collectAsState(initial = emptyList())
            ReadingHistoryScreen(
                readings = readings,
                onDelete = { id -> historyViewModel.deleteReading(id) }
            )
        }
    }
}

package com.example.palmistry.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.palmistry.data.model.ReadingEntity
import com.example.palmistry.data.repository.PalmistryRepository
import com.example.palmistry.security.EncryptionUtil
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import javax.inject.Inject

sealed class ReadingUiState {
    object Idle : ReadingUiState()
    object Loading : ReadingUiState()
    data class Success(val reading: String) : ReadingUiState()
    data class Error(val message: String) : ReadingUiState()
}

@HiltViewModel
class PalmistryViewModel @Inject constructor(
    private val repository: PalmistryRepository,
    private val encryptionUtil: EncryptionUtil
) : ViewModel() {

    private val _uiState = MutableStateFlow<ReadingUiState>(ReadingUiState.Idle)
    val uiState: StateFlow<ReadingUiState> = _uiState.asStateFlow()

    // Generate a new AES key per session (in production: load from Keystore)
    private val sessionKey = encryptionUtil.generateKey()

    val readingHistory = repository.getAllReadings()

    /**
     * Called when the palm is captured and TFLite returns the metadata JSON.
     */
    fun generateReading(palmJson: String, userQuestion: String = "Mera haath padhiye") {
        _uiState.value = ReadingUiState.Loading
        viewModelScope.launch {
            val metadata = mapOf("palm_json" to palmJson)
            val result = repository.generateReading(userQuestion, metadata, sessionKey)
            result.fold(
                onSuccess = { reading ->
                    _uiState.value = ReadingUiState.Success(reading)
                    // Save to local encrypted DB
                    repository.saveReadingLocally(
                        ReadingEntity(
                            palmMetadataJson = palmJson,
                            readingResult = reading,
                            lifeLineScore = 0f,
                            heartLineScore = 0f,
                            headLineScore = 0f,
                            fateLineScore = 0f,
                            confidenceScore = 0f
                        )
                    )
                },
                onFailure = { e ->
                    _uiState.value = ReadingUiState.Error(e.message ?: "Unknown error")
                }
            )
        }
    }

    /**
     * Direct method for continuous follow-up questions in the chat view.
     */
    fun generateReadingDirect(palmJson: String, onResult: (String) -> Unit) {
        viewModelScope.launch {
            val metadata = mapOf("palm_json" to palmJson)
            val result = repository.generateReading("Hastrekha Prashn", metadata, sessionKey)
            result.fold(
                onSuccess = { reading -> onResult(reading) },
                onFailure = { e -> onResult("⚠️ Upay Vishleshan error: ${e.message}") }
            )
        }
    }

    fun resetState() {
        _uiState.value = ReadingUiState.Idle
    }

    fun deleteReading(id: Int) {
        viewModelScope.launch { repository.deleteReading(id) }
    }
}

