@Composable
fun HomeScreen(
    selectedLanguage: String,
    onLanguageSelected: (String) -> Unit,
    onStartScan: () -> Unit,
    onOpenHistory: () -> Unit,
    onOpenCompatibility: () -> Unit
) {
